parameters.jsCode:
const data = items.map(item => item.json);

// Step 1: Group by sector
const sectorMap = {};

for (const row of data) {
  const sector = row.Sector;
  const value = parseFloat(row.Investment) || 0;

  if (!sectorMap[sector]) {
    sectorMap[sector] = 0;
  }

  sectorMap[sector] += value;
}

// Step 2: Total portfolio
const totalPortfolio = Object.values(sectorMap)
  .reduce((sum, val) => sum + val, 0);

// Step 3: Allocation %
const allocation = Object.entries(sectorMap).map(([sector, value]) => {
  return {
    sector,
    value,
    percentage: totalPortfolio === 0 
  ? 0 
  : parseFloat(((value / totalPortfolio) * 100).toFixed(2))
  };
});

return [
  {
    json: {
      allocation,
      totalPortfolio
    }
  }
];

const data = items[0].json;

const allocation = data.allocation || [];

let highestRisk = 0;
let riskLevel = "Low";

if (allocation.length === 0) {
  return [{
    json: {
      ...data,
      riskScore: 0,
      riskLevel: "No Data",
      isOverexposed: false,
      overexposedSectors: []
    }
  }];
}
// Loop through each sector
for (const sector of allocation) {
  const percentage = sector.percentage;

  if (percentage > 50) {
    highestRisk = Math.max(highestRisk, 3);
  } else if (percentage >= 30) {
    highestRisk = Math.max(highestRisk, 2);
  } else {
    highestRisk = Math.max(highestRisk, 1);
  }
}

// Assign label
if (highestRisk === 3) {
  riskLevel = "High";
} else if (highestRisk === 2) {
  riskLevel = "Medium";
}
const overexposedSectors = allocation.filter(s => s.percentage > 40);
const isOverexposed = overexposedSectors.length > 0;
// Return enriched data
return [
  {
    json: {
      ...data,
      riskScore: highestRisk,
      riskLevel,
      isOverexposed,
      overexposedSectors
    }
  }
];

const data = items[0].json;
const allocation = data.allocation || [];

// Number of sectors
const numSectors = allocation.length;

if (numSectors === 0) {
  return [{
    json: {
      ...data,
      diversificationScore: 0,
      diversificationLevel: "Poor"
    }
  }];
}

// Balance factor
let balanceFactor = 0;

for (const sector of allocation) {
  const ideal = 100 / numSectors;
  const diff = Math.abs(sector.percentage - ideal);
  balanceFactor += diff;
}

balanceFactor = balanceFactor / numSectors;

// Score
const diversificationScore = Math.max(0, (100 - balanceFactor)).toFixed(2);

// Label
let diversificationLevel = "Poor";

if (diversificationScore > 80) {
  diversificationLevel = "Excellent";
} else if (diversificationScore > 60) {
  diversificationLevel = "Good";
} else if (diversificationScore > 40) {
  diversificationLevel = "Moderate";
}

return [{
  json: {
    ...data,
    diversificationScore: Number(diversificationScore),
    diversificationLevel
  }
}];

