const data = items[0].json;

const allocation = data.allocation || [];

const report = `
 Portfolio Report

Risk: ${data.riskLevel || "N/A"}
Diversification: ${data.diversificationLevel || "N/A"}

Allocation:
${allocation.length 
  ? allocation.map(s => `- ${s.sector}: ${s.percentage}%`).join("\n")
  : "No allocation data available"}

Insights:
${data.ai_response || "No insights generated"}
`;

return [{
  json: {
    ...data,
    report,
    timestamp: new Date().toISOString()
  }
}];

